# Terraform: ASG が複数の AZ にまたがることを保証します
resource "aws_autoscaling_group" "<example_resource_name>" {
  min_size = 1
  max_size = 1

  launch_template {
    id      = "<example_resource_id>"
    version = "$Latest"
  }

  vpc_zone_identifier = [
    "<subnet_id_az1>",
    "<subnet_id_az2>" # 重要：チェックを通過するために、異なる AZ の2つのサブネット
  ]
}
```
